  1â†’/**
  2â†’ * Workspace Query Hooks
  3â†’ * TanStack Query hooks for workspace-related data fetching
  4â†’ */
  5â†’
  6â†’import { useQuery, useMutation, useQueryClient, keepPreviousData } from "@tanstack/react-query";
  7â†’import { useMemo } from "react";
  8â†’import { produce } from "immer";
  9â†’import {
 10â†’  WorkspaceService,
 11â†’  type WorkspaceGitInfo,
 12â†’  type ManifestResponse,
 13â†’} from "./workspace.service";
 14â†’import { RepoService } from "@/features/repository/api/repository.service";
 15â†’import { queryKeys } from "@/shared/api/queryKeys";
 16â†’import type { Workspace, RepoGroup, DiffStats } from "../types";
 17â†’import type { PRStatus } from "@/shared/types";
 18â†’import { createOptimisticWorkspace } from "../lib/workspace.utils";
 19â†’import { track } from "@/platform/analytics";
 20â†’
 21â†’/**
 22â†’ * Fetch workspaces grouped by repository.
 23â†’ *
 24â†’ * Event-driven invalidation handles freshness â€” no polling needed.
 25â†’ * Refetches on mount and window focus for reconciliation.
 26â†’ */
 27â†’export function useWorkspacesByRepo(state: string = "ready,initializing") {
 28â†’  return useQuery({
 29â†’    queryKey: queryKeys.workspaces.byRepo(state),
 30â†’    queryFn: () => WorkspaceService.fetchByRepo(state),
 31â†’    staleTime: 5000,
 32â†’    refetchOnWindowFocus: "always",
 33â†’  });
 34â†’}
 35â†’
 36â†’/**
 37â†’ * Fetch global stats.
 38â†’ *
 39â†’ * Explicit invalidation + focus reconciliation â€” no polling.
 40â†’ */
 41â†’export function useStats() {
 42â†’  return useQuery({
 43â†’    queryKey: queryKeys.stats.all,
 44â†’    queryFn: () => RepoService.fetchStats(),
 45â†’    staleTime: 15_000,
 46â†’    refetchOnWindowFocus: "always",
 47â†’  });
 48â†’}
 49â†’
 50â†’/**
 51â†’ * Fetch diff stats for a specific workspace
 52â†’ * Conditionally polls only when workspace is actively working.
 53â†’ *
 54â†’ * When `isWatched` is true (file watcher active via notify crate),
 55â†’ * polling is disabled â€” cache invalidation comes from fs:changed events.
 56â†’ * Falls back to 5s polling when not watched.
 57â†’ *
 58â†’ * IMPORTANT: Requires workspaceState === "ready" to avoid fetching diffs
 59â†’ * against incomplete worktrees during initialization. Running git diff on
 60â†’ * an initializing worktree produces garbage (e.g. +500K/-1M) that gets
 61â†’ * cached for 30s, persisting as phantom diffs even after the workspace
 62â†’ * becomes ready. Guard here, not in the UI.
 63â†’ */
 64â†’export function useDiffStats(
 65â†’  workspaceId: string | null,
 66â†’  sessionStatus?: string | null,
 67â†’  workspace?: WorkspaceGitInfo,
 68â†’  isWatched: boolean = false,
 69â†’  workspaceState?: string | null
 70â†’) {
 71â†’  return useQuery({
 72â†’    queryKey: queryKeys.workspaces.diffStats(workspaceId || ""),
 73â†’    queryFn: () => WorkspaceService.fetchDiffStats(workspaceId!, workspace),
 74â†’    enabled: !!workspaceId && workspaceState === "ready",
 75â†’    staleTime: 30000,
 76â†’    // Events handle invalidation when watched; fall back to polling otherwise
 77â†’    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
 78â†’    refetchOnMount: "always",
 79â†’    refetchOnWindowFocus: true,
 80â†’  });
 81â†’}
 82â†’
 83â†’/**
 84â†’ * Fetch diff stats for all sidebar workspaces in bulk.
 85â†’ *
 86â†’ * Replaces per-item useDiffStats() in the sidebar (N hooks â†’ 1 query).
 87â†’ * - Initial load: fetches ALL ready workspaces in parallel batches of 15
 88â†’ * - Polling: only re-fetches workspaces with session_status === "working" (5s)
 89â†’ * - Idle: no polling (staleTime 30s, refetch on window focus)
 90â†’ * - On workspace list change: seeds from per-workspace cache, fetches only missing/working
 91â†’ *
 92â†’ * Guard: state === "ready" â€” initializing worktrees have incomplete git state
 93â†’ * (missing HEAD, partial index â†’ garbage diffs like +500K/-1M). Setup script
 94â†’ * diffs are fine â€” .gitignore handles them, and `git checkout -- .` in the
 95â†’ * init pipeline resets any tracked-file mutations from bun install.
 96â†’ */
 97â†’export function useBulkDiffStats(repoGroups: RepoGroup[]) {
 98â†’  const queryClient = useQueryClient();
 99â†’
100â†’  const workspaceInfoMap = useMemo(() => {
101â†’    const map = new Map<string, WorkspaceGitInfo>();
102â†’    repoGroups.forEach((g) => {
103â†’      g.workspaces.forEach((w) => {
104â†’        if (w.state !== "ready") return;
105â†’        map.set(w.id, {
106â†’          root_path: w.root_path,
107â†’          slug: w.slug,
108â†’          workspace_path: w.workspace_path,
109â†’          git_target_branch: w.git_target_branch ?? undefined,
110â†’          git_default_branch: w.git_default_branch,
111â†’        });
112â†’      });
113â†’    });
114â†’    return map;
115â†’  }, [repoGroups]);
116â†’
117â†’  // Stable, de-duplicated IDs for query key â€” only ready workspaces.
118â†’  const workspaceIds = useMemo(() => {
119â†’    const ids = repoGroups.flatMap((g) =>
120â†’      g.workspaces.filter((w) => w.state === "ready").map((w) => w.id)
121â†’    );
122â†’    return Array.from(new Set(ids)).sort();
123â†’  }, [repoGroups]);
124â†’
125â†’  // IDs of workspaces with active sessions â€” only these need polling.
126â†’  const workingIds = useMemo(() => {
127â†’    return repoGroups
128â†’      .flatMap((g) => g.workspaces)
129â†’      .filter((w) => w.state === "ready" && w.session_status === "working")
130â†’      .map((w) => w.id);
131â†’  }, [repoGroups]);
132â†’
133â†’  const hasWorkingWorkspaces = workingIds.length > 0;
134â†’
135â†’  return useQuery({
136â†’    queryKey: ["bulk-diff-stats", workspaceIds],
137â†’    enabled: workspaceIds.length > 0,
138â†’    staleTime: 30_000,
139â†’    placeholderData: keepPreviousData,
140â†’    refetchInterval: hasWorkingWorkspaces ? 5000 : false,
141â†’    refetchOnMount: "always",
142â†’    refetchOnWindowFocus: true,
143â†’    queryFn: async () => {
144â†’      // Seed from per-workspace cache for workspaces we already have data for
145â†’      const results: Record<string, DiffStats> = {};
146â†’      for (const id of workspaceIds) {
147â†’        const cached = queryClient.getQueryData<DiffStats>(queryKeys.workspaces.diffStats(id));
148â†’        if (cached) results[id] = cached;
149â†’      }
150â†’
151â†’      // Fetch: missing workspaces + working workspaces (need fresh data)
152â†’      const missingIds = workspaceIds.filter((id) => !(id in results));
153â†’      const idsToFetch = [...new Set([...missingIds, ...workingIds])];
154â†’
155â†’      if (idsToFetch.length === 0) return results;
156â†’
157â†’      // Parallel batches of 15 â€” balances throughput vs resource pressure
158â†’      const BATCH_SIZE = 15;
159â†’      for (let i = 0; i < idsToFetch.length; i += BATCH_SIZE) {
160â†’        const batch = idsToFetch.slice(i, i + BATCH_SIZE);
161â†’        const settled = await Promise.allSettled(
162â†’          batch.map((id) => WorkspaceService.fetchDiffStats(id, workspaceInfoMap.get(id)))
163â†’        );
164â†’
165â†’        batch.forEach((id, j) => {
166â†’          if (settled[j].status === "fulfilled") {
167â†’            results[id] = settled[j].value;
168â†’            queryClient.setQueryData(queryKeys.workspaces.diffStats(id), settled[j].value);
169â†’          }
170â†’        });
171â†’      }
172â†’
173â†’      return results;
174â†’    },
175â†’  });
176â†’}
177â†’
178â†’/**
179â†’ * Fetch file changes for a workspace
180â†’ * Conditionally polls only when workspace is actively working.
181â†’ *
182â†’ * When `isWatched` is true (file watcher active via notify crate),
183â†’ * polling is disabled â€” cache invalidation comes from fs:changed events.
184â†’ * Falls back to 5s polling when not watched.
185â†’ *
186â†’ * IMPORTANT: Requires workspaceState === "ready" â€” same guard as useDiffStats.
187â†’ * See useDiffStats comment for the full explanation of the phantom diff race.
188â†’ */
189â†’export function useFileChanges(
190â†’  workspaceId: string | null,
191â†’  sessionStatus?: string | null,
192â†’  workspace?: WorkspaceGitInfo,
193â†’  isWatched: boolean = false,
194â†’  workspaceState?: string | null
195â†’) {
196â†’  return useQuery({
197â†’    queryKey: queryKeys.workspaces.diffFiles(workspaceId || ""),
198â†’    queryFn: async () => {
199â†’      const result = await WorkspaceService.fetchDiffFiles(workspaceId!, workspace);
200â†’      return {
201â†’        files: result.files || [],
202â†’        truncated: result.truncated ?? false,
203â†’        totalCount: result.totalCount ?? result.files?.length ?? 0,
204â†’      };
205â†’    },
206â†’    enabled: !!workspaceId && workspaceState === "ready",
207â†’    staleTime: 30000,
208â†’    // Events handle invalidation when watched; fall back to polling otherwise
209â†’    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
210â†’    refetchOnMount: "always",
211â†’    refetchOnWindowFocus: true,
212â†’  });
213â†’}
214â†’
215â†’/**
216â†’ * Fetch uncommitted files for a workspace (HEAD â†’ workdir).
217â†’ * Tauri IPC only â€” polls when workspace is actively working.
218â†’ *
219â†’ * IMPORTANT: Requires workspaceState === "ready" â€” same guard as useDiffStats.
220â†’ */
221â†’export function useUncommittedFiles(
222â†’  workspaceId: string | null,
223â†’  sessionStatus?: string | null,
224â†’  workspace?: WorkspaceGitInfo,
225â†’  workspaceState?: string | null
226â†’) {
227â†’  return useQuery({
228â†’    queryKey: queryKeys.workspaces.uncommittedFiles(workspaceId || ""),
229â†’    queryFn: () => WorkspaceService.fetchUncommittedFiles(workspace),
230â†’    enabled: !!workspaceId && workspaceState === "ready",
231â†’    staleTime: 30000,
232â†’    refetchInterval: sessionStatus === "working" ? 5000 : false,
233â†’    refetchOnMount: "always",
234â†’    refetchOnWindowFocus: true,
235â†’  });
236â†’}
237â†’
238â†’/**
239â†’ * Fetch last-turn files for a workspace (checkpoint â†’ workdir).
240â†’ * Tauri IPC only â€” polls when workspace is actively working.
241â†’ *
242â†’ * IMPORTANT: Requires workspaceState === "ready" â€” same guard as useDiffStats.
243â†’ */
244â†’export function useLastTurnFiles(
245â†’  workspaceId: string | null,
246â†’  sessionId: string | null | undefined,
247â†’  sessionStatus?: string | null,
248â†’  workspace?: WorkspaceGitInfo,
249â†’  workspaceState?: string | null
250â†’) {
251â†’  return useQuery({
252â†’    queryKey: queryKeys.workspaces.lastTurnFiles(workspaceId || "", sessionId || undefined),
253â†’    queryFn: () => WorkspaceService.fetchLastTurnFiles(workspace, sessionId || undefined),
254â†’    enabled: !!workspaceId && !!sessionId && workspaceState === "ready",
255â†’    staleTime: 30000,
256â†’    refetchInterval: sessionStatus === "working" ? 5000 : false,
257â†’    refetchOnMount: "always",
258â†’    refetchOnWindowFocus: true,
259â†’  });
260â†’}
261â†’
262â†’/**
263â†’ * Check GitHub CLI availability and auth status.
264â†’ * Cached with 5-minute staleTime â€” rarely changes during a session.
265â†’ * Gates usePRStatus to avoid wasted gh calls when CLI is missing or unauthenticated.
266â†’ */
267â†’export function useGhStatus() {
268â†’  return useQuery({
269â†’    queryKey: queryKeys.github.ghStatus,
270â†’    queryFn: () => WorkspaceService.fetchGhStatus(),
271â†’    staleTime: 5 * 60 * 1000, // 5 minutes
272â†’    refetchOnWindowFocus: false,
273â†’  });
274â†’}
275â†’
276â†’/**
277â†’ * Fetch PR status for a workspace.
278â†’ *
279â†’ * Gated on gh CLI being installed + authenticated (like Codex).
280â†’ * Polls every 30s while agent is working (to detect PR creation),
281â†’ * 60s while CI is pending post-session (CI runs 2-15min after push),
282â†’ * stops polling otherwise. Auto-refetched on session completion
283â†’ * via useSessionEvents invalidation.
284â†’ */
285â†’export function usePRStatus(
286â†’  workspaceId: string | null,
287â†’  options?: { ghInstalled?: boolean; ghAuthenticated?: boolean; sessionStatus?: string }
288â†’) {
289â†’  const { ghInstalled = true, ghAuthenticated = true, sessionStatus } = options ?? {};
290â†’  return useQuery({
291â†’    queryKey: queryKeys.workspaces.prStatus(workspaceId || ""),
292â†’    queryFn: () => WorkspaceService.fetchPRStatus(workspaceId!),
293â†’    enabled: !!workspaceId && ghInstalled && ghAuthenticated,
294â†’    staleTime: 10_000,
295â†’    refetchInterval: (query) => {
296â†’      // While agent is working: poll every 30s to detect PR creation/updates.
297â†’      if (sessionStatus === "working") return 30_000;
298â†’
299â†’      // After agent stops: CI checks typically run 2-15min. Poll every 60s
300â†’      // while CI is pending so the user sees updates without manual refresh.
301â†’      const data = query.state.data as PRStatus | null | undefined;
302â†’      if (data?.has_pr && data?.ci_status === "pending") return 60_000;
303â†’
304â†’      // No PR or CI resolved: stop polling. Window focus refetch handles edge cases.
305â†’      return false;
306â†’    },
307â†’    refetchOnWindowFocus: true,
308â†’  });
309â†’}
310â†’
311â†’/**
312â†’ * Fetch specific file diff
313â†’ */
314â†’export function useFileDiff(
315â†’  workspaceId: string | null,
316â†’  filePath: string | null,
317â†’  workspace?: WorkspaceGitInfo
318â†’) {
319â†’  return useQuery({
320â†’    queryKey: queryKeys.workspaces.diffFile(workspaceId || "", filePath || ""),
321â†’    queryFn: async () => {
322â†’      const result = await WorkspaceService.fetchFileDiff(workspaceId!, filePath!, workspace);
323â†’      return result;
324â†’    },
325â†’    enabled: !!workspaceId && !!filePath,
326â†’    staleTime: 10000, // Cache for 10s since diffs are expensive
327â†’  });
328â†’}
329â†’
330â†’/**
331â†’ * Create workspace mutation with optimistic update.
332â†’ *
333â†’ * Flow:
334â†’ * 1. User clicks "+" â†’ placeholder workspace appears instantly in sidebar
335â†’ * 2. Backend creates workspace (state = "initializing"), returns it
336â†’ * 3. onSuccess replaces placeholder with real data, triggers refetch
337â†’ * 4. Workspace progress events + terminal invalidation catch the ready transition
338â†’ */
339â†’export function useCreateWorkspace() {
340â†’  const queryClient = useQueryClient();
341â†’  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
342â†’
343â†’  return useMutation({
344â†’    mutationFn: (repositoryId: string) => WorkspaceService.create(repositoryId),
345â†’
346â†’    onMutate: async (repositoryId: string) => {
347â†’      await queryClient.cancelQueries({ queryKey });
348â†’
349â†’      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);
350â†’
351â†’      // Inject a placeholder workspace into the matching repo group
352â†’      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
353â†’        if (!old) return old;
354â†’        return produce(old, (draft) => {
355â†’          const repoGroup = draft.find((g) => g.repo_id === repositoryId);
356â†’          if (repoGroup) {
357â†’            repoGroup.workspaces.unshift(
358â†’              createOptimisticWorkspace(repositoryId, repoGroup.repo_name)
359â†’            );
360â†’          }
361â†’        });
362â†’      });
363â†’
364â†’      return { previousData };
365â†’    },
366â†’
367â†’    onError: (_err, _repositoryId, context) => {
368â†’      if (context?.previousData) {
369â†’        queryClient.setQueryData(queryKey, context.previousData);
370â†’      }
371â†’    },
372â†’
373â†’    onSuccess: (_data, repositoryId) => {
374â†’      track("workspace_created", { repository_id: repositoryId });
375â†’    },
376â†’
377â†’    onSettled: () => {
378â†’      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
379â†’    },
380â†’  });
381â†’}
382â†’
383â†’/**
384â†’ * Fetch available branches for a workspace/repo.
385â†’ * Uses Tauri IPC (fast, libgit2). Returns [] gracefully in browser/Storybook.
386â†’ */
387â†’export function useBranches(workspacePath: string | null) {
388â†’  return useQuery({
389â†’    queryKey: ["branches", workspacePath],
390â†’    queryFn: async () => {
391â†’      const { isTauriAvailable } = await import("@/platform/tauri/invoke");
392â†’      if (!isTauriAvailable()) {
393â†’        return [];
394â†’      }
395â†’      const { gitListBranches } = await import("@/platform/tauri/git");
396â†’      return await gitListBranches(workspacePath!);
397â†’    },
398â†’    enabled: !!workspacePath,
399â†’    staleTime: 30_000,
400â†’  });
401â†’}
402â†’
403â†’/**
404â†’ * Archive workspace mutation with optimistic update
405â†’ *
406â†’ * Flow:
407â†’ * 1. User clicks archive â†’ UI updates IMMEDIATELY (workspace removed from list)
408â†’ * 2. HTTP request sent in background
409â†’ * 3. Success: Cache already correct, refetch confirms
410â†’ * 4. Error: Rollback to previous state, show error
411â†’ */
412â†’export function useArchiveWorkspace() {
413â†’  const queryClient = useQueryClient();
414â†’  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");
415â†’
416â†’  return useMutation({
417â†’    mutationFn: (workspaceId: string) => WorkspaceService.archive(workspaceId),
418â†’
419â†’    // Optimistic update: Remove workspace from UI immediately
420â†’    onMutate: async (workspaceId: string) => {
421â†’      // Cancel any outgoing refetches (so they don't overwrite our optimistic update)
422â†’      await queryClient.cancelQueries({ queryKey });
423â†’
424â†’      // Snapshot the previous value
425â†’      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);
426â†’
427â†’      // Optimistically remove the workspace from the list
428â†’      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
429â†’        if (!old) return old;
430â†’        return produce(old, (draft) => {
431â†’          for (const repo of draft) {
432â†’            const index = repo.workspaces.findIndex((w) => w.id === workspaceId);
433â†’            if (index !== -1) {
434â†’              repo.workspaces.splice(index, 1);
435â†’              break;
436â†’            }
437â†’          }
438â†’        });
439â†’      });
440â†’
441â†’      // Return context with the previous value for rollback
442â†’      return { previousData };
443â†’    },
444â†’
445â†’    // If mutation fails, roll back to the previous value
446â†’    onError: (_err, _workspaceId, context) => {
447â†’      if (context?.previousData) {
448â†’        queryClient.setQueryData(queryKey, context.previousData);
449â†’      }
450â†’    },
451â†’
452â†’    onSuccess: (_data, workspaceId) => {
453â†’      track("workspace_archived", { workspace_id: workspaceId });
454â†’    },
455â†’
456â†’    // Always refetch after error or success to ensure consistency
457â†’    onSettled: () => {
458â†’      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
459â†’    },
460â†’  });
461â†’}
462â†’
463â†’/**
464â†’ * Unarchive workspace mutation â€” restores state to "ready".
465â†’ * Used by the undo toast after archiving.
466â†’ */
467â†’export function useUnarchiveWorkspace() {
468â†’  const queryClient = useQueryClient();
469â†’
470â†’  return useMutation({
471â†’    mutationFn: (workspaceId: string) => WorkspaceService.update(workspaceId, { state: "ready" }),
472â†’    onSuccess: (_data, workspaceId) => {
473â†’      track("workspace_unarchived", { workspace_id: workspaceId });
474â†’    },
475â†’    onSettled: () => {
476â†’      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
477â†’    },
478â†’  });
479â†’}
480â†’
481â†’/**
482â†’ * Fetch system prompt for a workspace
483â†’ */
484â†’export function useSystemPrompt(workspaceId: string | null) {
485â†’  return useQuery({
486â†’    queryKey: queryKeys.workspaces.systemPrompt(workspaceId || ""),
487â†’    queryFn: async () => {
488â†’      const result = await WorkspaceService.fetchSystemPrompt(workspaceId!);
489â†’      return result.system_prompt || "";
490â†’    },
491â†’    enabled: !!workspaceId,
492â†’    staleTime: 30000, // System prompts don't change often
493â†’  });
494â†’}
495â†’
496â†’/**
497â†’ * Update system prompt mutation with optimistic update
498â†’ */
499â†’export function useUpdateSystemPrompt() {
500â†’  const queryClient = useQueryClient();
