/**
 * Workspace Query Hooks
 * TanStack Query hooks for workspace-related data fetching
 */

import { useQuery, useMutation, useQueryClient, keepPreviousData } from "@tanstack/react-query";
import { useMemo } from "react";
import { produce } from "immer";
import {
  WorkspaceService,
  type WorkspaceGitInfo,
  type ManifestResponse,
} from "./workspace.service";
import { RepoService } from "@/features/repository/api/repository.service";
import { queryKeys } from "@/shared/api/queryKeys";
import type { Workspace, RepoGroup, DiffStats } from "../types";
import type { PRStatus } from "@/shared/types";
import { createOptimisticWorkspace } from "../lib/workspace.utils";
import { track } from "@/platform/analytics";

/**
 * Fetch workspaces grouped by repository.
 *
 * Event-driven invalidation handles freshness â€” no polling needed.
 * Refetches on mount and window focus for reconciliation.
 */
export function useWorkspacesByRepo(state: string = "ready,initializing") {
  return useQuery({
    queryKey: queryKeys.workspaces.byRepo(state),
    queryFn: () => WorkspaceService.fetchByRepo(state),
    staleTime: 5000,
    refetchOnWindowFocus: "always",
  });
}

/**
 * Fetch global stats.
 *
 * Explicit invalidation + focus reconciliation â€” no polling.
 */
export function useStats() {
  return useQuery({
    queryKey: queryKeys.stats.all,
    queryFn: () => RepoService.fetchStats(),
    staleTime: 15_000,
    refetchOnWindowFocus: "always",
  });
}

/**
 * Fetch diff stats for a specific workspace
 * Conditionally polls only when workspace is actively working.
 *
 * When `isWatched` is true (file watcher active via notify crate),
 * polling is disabled â€” cache invalidation comes from fs:changed events.
 * Falls back to 5s polling when not watched.
 *
 * IMPORTANT: Requires workspaceState === "ready" to avoid fetching diffs
 * against incomplete worktrees during initialization. Running git diff on
 * an initializing worktree produces garbage (e.g. +500K/-1M) that gets
 * cached for 30s, persisting as phantom diffs even after the workspace
 * becomes ready. Guard here, not in the UI.
 */
export function useDiffStats(
  workspaceId: string | null,
  sessionStatus?: string | null,
  workspace?: WorkspaceGitInfo,
  isWatched: boolean = false,
  workspaceState?: string | null
) {
  return useQuery({
    queryKey: queryKeys.workspaces.diffStats(workspaceId || ""),
    queryFn: () => WorkspaceService.fetchDiffStats(workspaceId!, workspace),
    enabled: !!workspaceId && workspaceState === "ready",
    staleTime: 30000,
    // Events handle invalidation when watched; fall back to polling otherwise
    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
    refetchOnMount: "always",
    refetchOnWindowFocus: true,
  });
}

/**
 * Fetch diff stats for all sidebar workspaces in bulk.
 *
 * Replaces per-item useDiffStats() in the sidebar (N hooks â†’ 1 query).
 * - Initial load: fetches ALL ready workspaces in parallel batches of 15
 * - Polling: only re-fetches workspaces with session_status === "working" (5s)
 * - Idle: no polling (staleTime 30s, refetch on window focus)
 * - On workspace list change: seeds from per-workspace cache, fetches only missing/working
 *
 * Guard: state === "ready" â€” initializing worktrees have incomplete git state
 * (missing HEAD, partial index â†’ garbage diffs like +500K/-1M). Setup script
 * diffs are fine â€” .gitignore handles them, and `git checkout -- .` in the
 * init pipeline resets any tracked-file mutations from bun install.
 */
export function useBulkDiffStats(repoGroups: RepoGroup[]) {
  const queryClient = useQueryClient();

  const workspaceInfoMap = useMemo(() => {
    const map = new Map<string, WorkspaceGitInfo>();
    repoGroups.forEach((g) => {
      g.workspaces.forEach((w) => {
        if (w.state !== "ready") return;
        map.set(w.id, {
          root_path: w.root_path,
          slug: w.slug,
          workspace_path: w.workspace_path,
          git_target_branch: w.git_target_branch ?? undefined,
          git_default_branch: w.git_default_branch,
        });
      });
    });
    return map;
  }, [repoGroups]);

  // Stable, de-duplicated IDs for query key â€” only ready workspaces.
  const workspaceIds = useMemo(() => {
    const ids = repoGroups.flatMap((g) =>
      g.workspaces.filter((w) => w.state === "ready").map((w) => w.id)
    );
    return Array.from(new Set(ids)).sort();
  }, [repoGroups]);

  // IDs of workspaces with active sessions â€” only these need polling.
  const workingIds = useMemo(() => {
    return repoGroups
      .flatMap((g) => g.workspaces)
      .filter((w) => w.state === "ready" && w.session_status === "working")
      .map((w) => w.id);
  }, [repoGroups]);

  const hasWorkingWorkspaces = workingIds.length > 0;

  return useQuery({
    queryKey: ["bulk-diff-stats", workspaceIds],
    enabled: workspaceIds.length > 0,
    staleTime: 30_000,
    placeholderData: keepPreviousData,
    refetchInterval: hasWorkingWorkspaces ? 5000 : false,
    refetchOnMount: "always",
    refetchOnWindowFocus: true,
    queryFn: async () => {
      // Seed from per-workspace cache for workspaces we already have data for
      const results: Record<string, DiffStats> = {};
      for (const id of workspaceIds) {
        const cached = queryClient.getQueryData<DiffStats>(queryKeys.workspaces.diffStats(id));
        if (cached) results[id] = cached;
      }

      // Fetch: missing workspaces + working workspaces (need fresh data)
      const missingIds = workspaceIds.filter((id) => !(id in results));
      const idsToFetch = [...new Set([...missingIds, ...workingIds])];

      if (idsToFetch.length === 0) return results;

      // Parallel batches of 15 â€” balances throughput vs resource pressure
      const BATCH_SIZE = 15;
      for (let i = 0; i < idsToFetch.length; i += BATCH_SIZE) {
        const batch = idsToFetch.slice(i, i + BATCH_SIZE);
        const settled = await Promise.allSettled(
          batch.map((id) => WorkspaceService.fetchDiffStats(id, workspaceInfoMap.get(id)))
        );

        batch.forEach((id, j) => {
          if (settled[j].status === "fulfilled") {
            results[id] = settled[j].value;
            queryClient.setQueryData(queryKeys.workspaces.diffStats(id), settled[j].value);
          }
        });
      }

      return results;
    },
  });
}

/**
 * Fetch file changes for a workspace
 * Conditionally polls only when workspace is actively working.
 *
 * When `isWatched` is true (file watcher active via notify crate),
 * polling is disabled â€” cache invalidation comes from fs:changed events.
 * Falls back to 5s polling when not watched.
 *
 * IMPORTANT: Requires workspaceState === "ready" â€” same guard as useDiffStats.
 * See useDiffStats comment for the full explanation of the phantom diff race.
 */
export function useFileChanges(
  workspaceId: string | null,
  sessionStatus?: string | null,
  workspace?: WorkspaceGitInfo,
  isWatched: boolean = false,
  workspaceState?: string | null
) {
  return useQuery({
    queryKey: queryKeys.workspaces.diffFiles(workspaceId || ""),
    queryFn: async () => {
      const result = await WorkspaceService.fetchDiffFiles(workspaceId!, workspace);
      return {
        files: result.files || [],
        truncated: result.truncated ?? false,
        totalCount: result.totalCount ?? result.files?.length ?? 0,
      };
    },
    enabled: !!workspaceId && workspaceState === "ready",
    staleTime: 30000,
    // Events handle invalidation when watched; fall back to polling otherwise
    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
    refetchOnMount: "always",
    refetchOnWindowFocus: true,
  });
}

/**
 * Fetch uncommitted files for a workspace (HEAD â†’ workdir).
 * Tauri IPC only â€” polls when workspace is actively working.
 *
 * IMPORTANT: Requires workspaceState === "ready" â€” same guard as useDiffStats.
 */
export function useUncommittedFiles(
  workspaceId: string | null,
  sessionStatus?: string | null,
  workspace?: WorkspaceGitInfo,
  workspaceState?: string | null
) {
  return useQuery({
    queryKey: queryKeys.workspaces.uncommittedFiles(workspaceId || ""),
    queryFn: () => WorkspaceService.fetchUncommittedFiles(workspace),
    enabled: !!workspaceId && workspaceState === "ready",
    staleTime: 30000,
    refetchInterval: sessionStatus === "working" ? 5000 : false,
    refetchOnMount: "always",
    refetchOnWindowFocus: true,
  });
}

/**
 * Fetch last-turn files for a workspace (checkpoint â†’ workdir).
 * Tauri IPC only â€” polls when workspace is actively working.
 *
 * IMPORTANT: Requires workspaceState === "ready" â€” same guard as useDiffStats.
 */
export function useLastTurnFiles(
  workspaceId: string | null,
  sessionId: string | null | undefined,
  sessionStatus?: string | null,
  workspace?: WorkspaceGitInfo,
  workspaceState?: string | null
) {
  return useQuery({
    queryKey: queryKeys.workspaces.lastTurnFiles(workspaceId || "", sessionId || undefined),
    queryFn: () => WorkspaceService.fetchLastTurnFiles(workspace, sessionId || undefined),
    enabled: !!workspaceId && !!sessionId && workspaceState === "ready",
    staleTime: 30000,
    refetchInterval: sessionStatus === "working" ? 5000 : false,
    refetchOnMount: "always",
    refetchOnWindowFocus: true,
  });
}

/**
 * Check GitHub CLI availability and auth status.
 * Cached with 5-minute staleTime â€” rarely changes during a session.
 * Gates usePRStatus to avoid wasted gh calls when CLI is missing or unauthenticated.
 */
export function useGhStatus() {
  return useQuery({
    queryKey: queryKeys.github.ghStatus,
    queryFn: () => WorkspaceService.fetchGhStatus(),
    staleTime: 5 * 60 * 1000, // 5 minutes
    refetchOnWindowFocus: false,
  });
}

/**
 * Fetch PR status for a workspace.
 *
 * Gated on gh CLI being installed + authenticated (like Codex).
 * Polls every 30s while agent is working (to detect PR creation),
 * 60s while CI is pending post-session (CI runs 2-15min after push),
 * stops polling otherwise. Auto-refetched on session completion
 * via useSessionEvents invalidation.
 */
export function usePRStatus(
  workspaceId: string | null,
  options?: { ghInstalled?: boolean; ghAuthenticated?: boolean; sessionStatus?: string }
) {
  const { ghInstalled = true, ghAuthenticated = true, sessionStatus } = options ?? {};
  return useQuery({
    queryKey: queryKeys.workspaces.prStatus(workspaceId || ""),
    queryFn: () => WorkspaceService.fetchPRStatus(workspaceId!),
    enabled: !!workspaceId && ghInstalled && ghAuthenticated,
    staleTime: 10_000,
    refetchInterval: (query) => {
      // While agent is working: poll every 30s to detect PR creation/updates.
      if (sessionStatus === "working") return 30_000;

      // After agent stops: CI checks typically run 2-15min. Poll every 60s
      // while CI is pending so the user sees updates without manual refresh.
      const data = query.state.data as PRStatus | null | undefined;
      if (data?.has_pr && data?.ci_status === "pending") return 60_000;

      // No PR or CI resolved: stop polling. Window focus refetch handles edge cases.
      return false;
    },
    refetchOnWindowFocus: true,
  });
}

/**
 * Fetch specific file diff
 */
export function useFileDiff(
  workspaceId: string | null,
  filePath: string | null,
  workspace?: WorkspaceGitInfo
) {
  return useQuery({
    queryKey: queryKeys.workspaces.diffFile(workspaceId || "", filePath || ""),
    queryFn: async () => {
      const result = await WorkspaceService.fetchFileDiff(workspaceId!, filePath!, workspace);
      return result;
    },
    enabled: !!workspaceId && !!filePath,
    staleTime: 10000, // Cache for 10s since diffs are expensive
  });
}

/**
 * Create workspace mutation with optimistic update.
 *
 * Flow:
 * 1. User clicks "+" â†’ placeholder workspace appears instantly in sidebar
 * 2. Backend creates workspace (state = "initializing"), returns it
 * 3. onSuccess replaces placeholder with real data, triggers refetch
 * 4. Workspace progress events + terminal invalidation catch the ready transition
 */
export function useCreateWorkspace() {
  const queryClient = useQueryClient();
  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");

  return useMutation({
    mutationFn: (repositoryId: string) => WorkspaceService.create(repositoryId),

    onMutate: async (repositoryId: string) => {
      await queryClient.cancelQueries({ queryKey });

      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);

      // Inject a placeholder workspace into the matching repo group
      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
        if (!old) return old;
        return produce(old, (draft) => {
          const repoGroup = draft.find((g) => g.repo_id === repositoryId);
          if (repoGroup) {
            repoGroup.workspaces.unshift(
              createOptimisticWorkspace(repositoryId, repoGroup.repo_name)
            );
          }
        });
      });

      return { previousData };
    },

    onError: (_err, _repositoryId, context) => {
      if (context?.previousData) {
        queryClient.setQueryData(queryKey, context.previousData);
      }
    },

    onSuccess: (_data, repositoryId) => {
      track("workspace_created", { repository_id: repositoryId });
    },

    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
    },
  });
}

/**
 * Fetch available branches for a workspace/repo.
 * Uses Tauri IPC (fast, libgit2). Returns [] gracefully in browser/Storybook.
 */
export function useBranches(workspacePath: string | null) {
  return useQuery({
    queryKey: ["branches", workspacePath],
    queryFn: async () => {
      const { isTauriAvailable } = await import("@/platform/tauri/invoke");
      if (!isTauriAvailable()) {
        return [];
      }
      const { gitListBranches } = await import("@/platform/tauri/git");
      return await gitListBranches(workspacePath!);
    },
    enabled: !!workspacePath,
    staleTime: 30_000,
  });
}

/**
 * Archive workspace mutation with optimistic update
 *
 * Flow:
 * 1. User clicks archive â†’ UI updates IMMEDIATELY (workspace removed from list)
 * 2. HTTP request sent in background
 * 3. Success: Cache already correct, refetch confirms
 * 4. Error: Rollback to previous state, show error
 */
export function useArchiveWorkspace() {
  const queryClient = useQueryClient();
  const queryKey = queryKeys.workspaces.byRepo("ready,initializing");

  return useMutation({
    mutationFn: (workspaceId: string) => WorkspaceService.archive(workspaceId),

    // Optimistic update: Remove workspace from UI immediately
    onMutate: async (workspaceId: string) => {
      // Cancel any outgoing refetches (so they don't overwrite our optimistic update)
      await queryClient.cancelQueries({ queryKey });

      // Snapshot the previous value
      const previousData = queryClient.getQueryData<RepoGroup[]>(queryKey);

      // Optimistically remove the workspace from the list
      queryClient.setQueryData<RepoGroup[]>(queryKey, (old) => {
        if (!old) return old;
        return produce(old, (draft) => {
          for (const repo of draft) {
            const index = repo.workspaces.findIndex((w) => w.id === workspaceId);
            if (index !== -1) {
              repo.workspaces.splice(index, 1);
              break;
            }
          }
        });
      });

      // Return context with the previous value for rollback
      return { previousData };
    },

    // If mutation fails, roll back to the previous value
    onError: (_err, _workspaceId, context) => {
      if (context?.previousData) {
        queryClient.setQueryData(queryKey, context.previousData);
      }
    },

    onSuccess: (_data, workspaceId) => {
      track("workspace_archived", { workspace_id: workspaceId });
    },

    // Always refetch after error or success to ensure consistency
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
    },
  });
}

/**
 * Unarchive workspace mutation â€” restores state to "ready".
 * Used by the undo toast after archiving.
 */
export function useUnarchiveWorkspace() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (workspaceId: string) => WorkspaceService.update(workspaceId, { state: "ready" }),
    onSuccess: (_data, workspaceId) => {
      track("workspace_unarchived", { workspace_id: workspaceId });
    },
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
    },
  });
}

/**
 * Fetch system prompt for a workspace
 */
export function useSystemPrompt(workspaceId: string | null) {
  return useQuery({
    queryKey: queryKeys.workspaces.systemPrompt(workspaceId || ""),
    queryFn: async () => {
      const result = await WorkspaceService.fetchSystemPrompt(workspaceId!);
      return result.system_prompt || "";
    },
    enabled: !!workspaceId,
    staleTime: 30000, // System prompts don't change often
  });
}

/**
 * Update system prompt mutation with optimistic update
 */
export function useUpdateSystemPrompt() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: ({ workspaceId, systemPrompt }: { workspaceId: string; systemPrompt: string }) =>
      WorkspaceService.updateSystemPrompt(workspaceId, systemPrompt),

    // Optimistic update: Show new prompt immediately
    onMutate: async ({ workspaceId, systemPrompt }) => {
      await queryClient.cancelQueries({
        queryKey: queryKeys.workspaces.systemPrompt(workspaceId),
      });

      const previousPrompt = queryClient.getQueryData<string>(
        queryKeys.workspaces.systemPrompt(workspaceId)
      );

      queryClient.setQueryData(queryKeys.workspaces.systemPrompt(workspaceId), systemPrompt);

      return { previousPrompt };
    },

    onError: (_err, variables, context) => {
      if (context?.previousPrompt !== undefined) {
        queryClient.setQueryData(
          queryKeys.workspaces.systemPrompt(variables.workspaceId),
          context.previousPrompt
        );
      }
    },

    onSettled: (_, __, variables) => {
      queryClient.invalidateQueries({
        queryKey: queryKeys.workspaces.systemPrompt(variables.workspaceId),
      });
    },
  });
}

/**
 * Fetch opendevs.json manifest + normalized tasks for a workspace.
 * Manifest doesn't change during a session â€” staleTime: Infinity.
 */
export function useManifestTasks(workspaceId: string | null) {
  return useQuery({
    queryKey: queryKeys.workspaces.manifest(workspaceId || ""),
    queryFn: () => WorkspaceService.fetchManifest(workspaceId!),
    enabled: !!workspaceId,
    staleTime: Infinity,
  });
}

/**
 * Retry failed setup for a workspace.
 * Invalidates workspace queries to refresh setup_status.
 */
export function useRetrySetup() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (workspaceId: string) => WorkspaceService.retrySetup(workspaceId),
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
    },
  });
}

/**
 * Workspace Layout Store
 *
 * Per-workspace layout state persistence for right panel, files, and browser.
 * Each workspace remembers its own layout configuration independently.
 *
 * Key Features:
 * - Workspace-specific state (not shared between workspaces)
 * - LocalStorage persistence (survives app restarts)
 * - Automatic restoration on workspace switch
 *
 * State Structure:
 * {
 *   [workspaceId]: {
 *     activeRightTab: 'changes' | 'files'  // Code panel tab
 *     activeRightSideTab: 'code' | 'config' | 'terminal' | 'notebook' | 'design' | 'browser' | 'simulator' // Sidecar panel
 *     selectedFile: { path: string, source: 'changes' | 'files' } | null
 *     sidebarCollapsed: boolean            // Left sidebar state
 *     chatPanelCollapsed: boolean          // Chat panel collapsed via resizable panels
 *     rightPanelCollapsed: boolean         // Content panel collapsed via resizable panels
 *   }
 * }
 */

import { create } from "zustand";
import { devtools, persist } from "zustand/middleware";
import type { PersistedBrowserTab } from "@/features/browser/types";

export type RightPanelTab = "changes" | "files";
export type RightSideTab = "code" | "config" | "terminal" | "notebook" | "design" | "browser" | "simulator";

export interface SelectedFile {
  path: string;
  source: "changes" | "files";
}

export interface PersistedTerminalTab {
  id: string;
  title: string;
}

interface WorkspaceLayoutState {
  activeRightTab: RightPanelTab;
  activeRightSideTab: RightSideTab;
  selectedFile: SelectedFile | null;
  sidebarCollapsed: boolean;
  browserTabs: PersistedBrowserTab[]; // Persisted browser tab URLs/titles
  activeBrowserTabId: string | null; // Which browser tab was last active
  chatPanelCollapsed: boolean;
  rightPanelCollapsed: boolean;
  chatTabSessionIds: string[]; // Ordered session IDs for open chat tabs
  activeChatTabSessionId: string | null; // Which chat tab is active
  pendingTerminalCommand: string | null; // Command to auto-run in a new terminal tab (e.g. "claude login")
  simulatorUdid: string | null; // Last-used simulator UDID for this workspace
  terminalTabs: PersistedTerminalTab[]; // Per-workspace terminal tab metadata
  activeTerminalTabId: string | null; // Which terminal tab is active
  nextTerminalNum: number; // Counter for "Terminal N" naming
}

interface WorkspaceLayoutStore {
  // State: Record of workspace ID â†’ layout state
  layouts: Record<string, WorkspaceLayoutState>;

  // Getters
  /**
   * Get layout state for a specific workspace (with defaults if not set)
   */
  getLayout: (workspaceId: string) => WorkspaceLayoutState;

  // Setters - Full state updates
  /**
   * Set complete layout state for a workspace
   */
  setLayout: (workspaceId: string, layout: Partial<WorkspaceLayoutState>) => void;

  // Setters - Individual properties (convenience methods)
  /**
   * Switch active tab in right panel
   */
  setActiveRightTab: (workspaceId: string, tab: RightPanelTab) => void;

  /**
   * Switch active tab in right side panel
   */
  setActiveRightSideTab: (workspaceId: string, tab: RightSideTab) => void;

  /**
   * Select a file to display in the panel
   */
  setSelectedFile: (workspaceId: string, file: SelectedFile | null) => void;

  /**
   * Toggle sidebar collapsed state
   */
  setSidebarCollapsed: (workspaceId: string, collapsed: boolean) => void;

  /**
   * Toggle chat panel collapsed state
   */
  setChatPanelCollapsed: (workspaceId: string, collapsed: boolean) => void;

  /**
   * Toggle right panel collapsed state
   */
  setRightPanelCollapsed: (workspaceId: string, collapsed: boolean) => void;

  /**
   * Set a command to auto-run in a new terminal tab
   */
  setPendingTerminalCommand: (workspaceId: string, command: string | null) => void;

  /**
   * Set the last-used simulator UDID for a workspace
   */
  setSimulatorUdid: (workspaceId: string, udid: string | null) => void;

  /**
   * Persist chat tab order and active tab for a workspace
   */
  setChatTabState: (
    workspaceId: string,
    sessionIds: string[],
    activeSessionId: string | null
  ) => void;

  /**
   * Persist terminal tab order, active tab, and naming counter for a workspace
   */
  setTerminalTabState: (
    workspaceId: string,
    tabs: PersistedTerminalTab[],
    activeTabId: string | null,
    nextNum: number
  ) => void;

  // Utilities
  /**
   * Clear layout state for a specific workspace
   */
  clearWorkspaceLayout: (workspaceId: string) => void;

  /**
   * Reset all layout state (useful for debugging)
   */
  resetAll: () => void;
}

export const defaultLayout: WorkspaceLayoutState = {
  activeRightTab: "changes",
  activeRightSideTab: "code",
  selectedFile: null,
  sidebarCollapsed: false,
  browserTabs: [],
  activeBrowserTabId: null,
  chatPanelCollapsed: false,
  rightPanelCollapsed: false,
  chatTabSessionIds: [],
  activeChatTabSessionId: null,
  pendingTerminalCommand: null,
  simulatorUdid: null,
  terminalTabs: [],
  activeTerminalTabId: null,
  nextTerminalNum: 1,
};

// Legacy fields that may exist in persisted data from older versions.
// Kept here so the migration code compiles without errors.
type PersistedLayoutV1 = Partial<WorkspaceLayoutState> & {
  rightPanelExpanded?: boolean;
  rightPanelWidth?: number | null;
  rightPanelWidthBrowser?: number | null;
};

type PersistedStateV1 = {
  layouts?: Record<string, PersistedLayoutV1>;
};

export const useWorkspaceLayoutStore = create<WorkspaceLayoutStore>()(
  devtools(
    persist(
      (set, get) => ({
        // Initial state
        layouts: {},

        // Getters
        getLayout: (workspaceId) => {
          const { layouts } = get();
          // Merge with defaults so newly-added fields (e.g. browserTabs)
          // are always present even for layouts persisted before they existed.
          return { ...defaultLayout, ...(layouts[workspaceId] ?? {}) };
        },

        // Setters - Full state
        setLayout: (workspaceId, updates) =>
          set(
            (state) => ({
              layouts: {
                ...state.layouts,
                [workspaceId]: {
                  ...defaultLayout,
                  ...state.layouts[workspaceId],
                  ...updates,
                },
              },
            }),
            false,
            "workspaceLayout/setLayout"
          ),

        // Setters - Individual properties
        setActiveRightTab: (workspaceId, tab) =>
          set(
            (state) => ({
              layouts: {
                ...state.layouts,
                [workspaceId]: {
                  ...(state.layouts[workspaceId] || defaultLayout),
                  activeRightTab: tab,
                },
              },
            }),
            false,
            "workspaceLayout/setActiveRightTab"
          ),

        setActiveRightSideTab: (workspaceId, tab) =>
          set(
            (state) => ({
              layouts: {
                ...state.layouts,
                [workspaceId]: {
                  ...(state.layouts[workspaceId] || defaultLayout),
                  activeRightSideTab: tab,
                },
              },
            }),
            false,
            "workspaceLayout/setActiveRightSideTab"
          ),

        setSelectedFile: (workspaceId, file) =>
          set(
            (state) => ({
              layouts: {
                ...state.layouts,
                [workspaceId]: {
                  ...(state.layouts[workspaceId] || defaultLayout),
                  selectedFile: file,
                },
              },
            }),
            false,
            "workspaceLayout/setSelectedFile"
          ),

        setSidebarCollapsed: (workspaceId, collapsed) =>
          set(
            (state) => ({
              layouts: {
                ...state.layouts,
                [workspaceId]: {
                  ...(state.layouts[workspaceId] || defaultLayout),
                  sidebarCollapsed: collapsed,
                },
              },
            }),
            false,
            "workspaceLayout/setSidebarCollapsed"
          ),

        setChatPanelCollapsed: (workspaceId, collapsed) =>
          set(
            (state) => ({
              layouts: {
                ...state.layouts,
                [workspaceId]: {
                  ...(state.layouts[workspaceId] || defaultLayout),
                  chatPanelCollapsed: collapsed,
                },
              },
            }),
            false,
            "workspaceLayout/setChatPanelCollapsed"
          ),

        setRightPanelCollapsed: (workspaceId, collapsed) =>
          set(
            (state) => ({
              layouts: {
                ...state.layouts,
                [workspaceId]: {
                  ...(state.layouts[workspaceId] || defaultLayout),
                  rightPanelCollapsed: collapsed,
                },
              },
            }),
            false,
            "workspaceLayout/setRightPanelCollapsed"
          ),

        setChatTabState: (workspaceId, sessionIds, activeSessionId) =>
          set(
            (state) => ({
              layouts: {
                ...state.layouts,
                [workspaceId]: {
                  ...(state.layouts[workspaceId] || defaultLayout),
                  chatTabSessionIds: sessionIds,
                  activeChatTabSessionId: activeSessionId,
                },
              },
            }),
            false,
            "workspaceLayout/setChatTabState"
          ),

        setTerminalTabState: (workspaceId, tabs, activeTabId, nextNum) =>
          set(
            (state) => ({
              layouts: {
                ...state.layouts,
                [workspaceId]: {
                  ...(state.layouts[workspaceId] || defaultLayout),
                  terminalTabs: tabs,
                  activeTerminalTabId: activeTabId,
                  nextTerminalNum: nextNum,
                },
              },
            }),
            false,
            "workspaceLayout/setTerminalTabState"
          ),

        setPendingTerminalCommand: (workspaceId, command) =>
          set(
            (state) => ({
              layouts: {
                ...state.layouts,
                [workspaceId]: {
                  ...(state.layouts[workspaceId] || defaultLayout),
                  pendingTerminalCommand: command,
                },
              },
            }),
            false,
            "workspaceLayout/setPendingTerminalCommand"
          ),

        setSimulatorUdid: (workspaceId, udid) =>
          set(
            (state) => ({
              layouts: {
                ...state.layouts,
                [workspaceId]: {
                  ...(state.layouts[workspaceId] || defaultLayout),
                  simulatorUdid: udid,
                },
              },
            }),
            false,
            "workspaceLayout/setSimulatorUdid"
          ),

        // Utilities
        clearWorkspaceLayout: (workspaceId) =>
          set(
            (state) => {
              const { [workspaceId]: _removed, ...remaining } = state.layouts;
              return { layouts: remaining };
            },
            false,
            "workspaceLayout/clearWorkspaceLayout"
          ),

        resetAll: () => set({ layouts: {} }, false, "workspaceLayout/resetAll"),
      }),
      {
        name: "workspace-layout-store", // localStorage key
        version: 9,
        // Strip ephemeral/runtime-only state that must not survive app restarts.
        // pendingTerminalCommand: transient signal consumed by TerminalPanel.
        // terminalTabs/activeTerminalTabId/nextTerminalNum: PTY processes don't
        // survive app restarts, so persisting tab metadata would create zombie
        // tabs with no backing shell process.
        partialize: (state) => ({
          ...state,
          layouts: Object.fromEntries(
            Object.entries(state.layouts).map(([id, layout]) => [
              id,
              {
                ...layout,
                pendingTerminalCommand: null,
                terminalTabs: [],
                activeTerminalTabId: null,
                nextTerminalNum: 1,
              },
            ])
          ),
        }),
        migrate: (persistedState: unknown, version: number) => {
          const state: PersistedStateV1 =
            typeof persistedState === "object" && persistedState !== null
              ? (persistedState as PersistedStateV1)
              : {};

          if (state.layouts && typeof state.layouts === "object") {
            const nextLayouts: Record<string, PersistedLayoutV1> = {};
            for (const [key, layout] of Object.entries(state.layouts)) {
              if (!layout || typeof layout !== "object") {
                continue;
              }
              const nextLayout: PersistedLayoutV1 = {
                ...layout,
              };

              if (version < 2) {
                nextLayout.rightPanelWidth =
                  "rightPanelWidth" in layout ? (layout.rightPanelWidth ?? null) : null;
              }

              if (version < 3) {
                nextLayout.rightPanelWidthBrowser =
                  "rightPanelWidthBrowser" in layout
                    ? (layout.rightPanelWidthBrowser ?? null)
                    : null;
              }

              // v4: Add browser tab persistence fields
              if (version < 4) {
                (nextLayout as Record<string, unknown>).browserTabs =
                  (layout as Record<string, unknown>).browserTabs ?? [];
                (nextLayout as Record<string, unknown>).activeBrowserTabId =
                  (layout as Record<string, unknown>).activeBrowserTabId ?? null;
              }

              // v5: Add chat panel collapsed state
              if (version < 5) {
                nextLayout.chatPanelCollapsed = false;
              }

              // v6: Add chat tab persistence fields
              if (version < 6) {
                (nextLayout as Record<string, unknown>).chatTabSessionIds = [];
                (nextLayout as Record<string, unknown>).activeChatTabSessionId = null;
              }

              // v7: Add right panel collapsed state
              if (version < 7) {
                nextLayout.rightPanelCollapsed = false;
              }

              // v8: Add simulator UDID persistence
              if (version < 8) {
                (nextLayout as Record<string, unknown>).simulatorUdid = null;
              }

              // v9: Add terminal tab state (runtime-only, stripped by partialize)
              if (version < 9) {
                (nextLayout as Record<string, unknown>).terminalTabs = [];
                (nextLayout as Record<string, unknown>).activeTerminalTabId = null;
                (nextLayout as Record<string, unknown>).nextTerminalNum = 1;
              }

              nextLayouts[key] = nextLayout;
            }
            return { ...state, layouts: nextLayouts } as WorkspaceLayoutStore;
          }

          return state as WorkspaceLayoutStore;
        },
      }
    ),
    {
      name: "workspace-layout-store",
      enabled: import.meta.env.DEV,
    }
  )
);

/**
 * Stable Actions - Call from anywhere without causing re-renders
 */
export const workspaceLayoutActions = {
  getLayout: (workspaceId: string) => useWorkspaceLayoutStore.getState().getLayout(workspaceId),
  setLayout: (workspaceId: string, layout: Partial<WorkspaceLayoutState>) =>
    useWorkspaceLayoutStore.getState().setLayout(workspaceId, layout),
  setActiveRightTab: (workspaceId: string, tab: RightPanelTab) =>
    useWorkspaceLayoutStore.getState().setActiveRightTab(workspaceId, tab),
  setActiveRightSideTab: (workspaceId: string, tab: RightSideTab) =>
    useWorkspaceLayoutStore.getState().setActiveRightSideTab(workspaceId, tab),
  setSelectedFile: (workspaceId: string, file: SelectedFile | null) =>
    useWorkspaceLayoutStore.getState().setSelectedFile(workspaceId, file),
  setSidebarCollapsed: (workspaceId: string, collapsed: boolean) =>
    useWorkspaceLayoutStore.getState().setSidebarCollapsed(workspaceId, collapsed),
  setChatPanelCollapsed: (workspaceId: string, collapsed: boolean) =>
    useWorkspaceLayoutStore.getState().setChatPanelCollapsed(workspaceId, collapsed),
  setRightPanelCollapsed: (workspaceId: string, collapsed: boolean) =>
    useWorkspaceLayoutStore.getState().setRightPanelCollapsed(workspaceId, collapsed),
  setChatTabState: (workspaceId: string, sessionIds: string[], activeSessionId: string | null) =>
    useWorkspaceLayoutStore.getState().setChatTabState(workspaceId, sessionIds, activeSessionId),
  setTerminalTabState: (
    workspaceId: string,
    tabs: PersistedTerminalTab[],
    activeTabId: string | null,
    nextNum: number
  ) => useWorkspaceLayoutStore.getState().setTerminalTabState(workspaceId, tabs, activeTabId, nextNum),
  setPendingTerminalCommand: (workspaceId: string, command: string | null) =>
    useWorkspaceLayoutStore.getState().setPendingTerminalCommand(workspaceId, command),
  setSimulatorUdid: (workspaceId: string, udid: string | null) =>
    useWorkspaceLayoutStore.getState().setSimulatorUdid(workspaceId, udid),
  clearWorkspaceLayout: (workspaceId: string) =>
    useWorkspaceLayoutStore.getState().clearWorkspaceLayout(workspaceId),
  resetAll: () => useWorkspaceLayoutStore.getState().resetAll(),
};

