  2â†’ * useResizeHandle â€” Drag-to-resize logic for panel splits.
  3â†’ *
  4â†’ * Supports both horizontal (left/right, col-resize) and vertical (top/bottom, row-resize).
  5â†’ * Tracks mousedown â†’ mousemove â†’ mouseup on a handle element.
  6â†’ * Returns props to spread onto the handle and an isDragging flag for styling.
  7â†’ * Double-click resets size to null (auto flex split).
  8â†’ */
  9â†’
 10â†’import { useCallback, useEffect, useRef, useState } from "react";
 11â†’
 12â†’interface UseResizeHandleOptions {
 13â†’  /** Callback to persist new size in pixels (null = auto) */
 14â†’  onSizeChange: (size: number | null) => void;
 15â†’  /** Whether resizing is enabled */
 16â†’  enabled: boolean;
 17â†’  /** Resize direction: horizontal = left/right split, vertical = top/bottom split */
 18â†’  direction?: "horizontal" | "vertical";
 19â†’  /** Which panel the reported size refers to.
 20â†’   *  "secondary" (default) = right/bottom panel width/height.
 21â†’   *  "primary" = left/top panel width/height (useful for sidebar resize). */
 22â†’  mode?: "secondary" | "primary";
 23â†’  /** Min size of the secondary (right or bottom) panel in pixels */
 24â†’  minSecondarySize?: number;
 25â†’  /** Min size of the primary (left or top) panel in pixels */
 26â†’  minPrimarySize?: number;
 27â†’  /** Called when the user drags the primary panel well below minPrimarySize
 28â†’   *  (past a 50% dead zone). The panel first clamps at minPrimarySize; only
 29â†’   *  dragging past half that value triggers the collapse callback. */
 30â†’  onPrimaryCollapse?: () => void;
 31â†’  /** Whether the primary panel is currently collapsed (for bidirectional drag gestures) */
 32â†’  isPrimaryCollapsed?: boolean;
 33â†’  /** Called when the user drags back past the expand threshold while collapsed */
 34â†’  onPrimaryExpand?: () => void;
 35â†’}
 36â†’
 37â†’interface UseResizeHandleReturn {
 38â†’  handleProps: {
 39â†’    onMouseDown: (e: React.MouseEvent) => void;
 40â†’    onDoubleClick: () => void;
 41â†’  };
 42â†’  isDragging: boolean;
 43â†’}
 44â†’
 45â†’export function useResizeHandle({
 46â†’  onSizeChange,
 47â†’  enabled,
 48â†’  direction = "horizontal",
 49â†’  mode = "secondary",
 50â†’  minSecondarySize = 380,
 51â†’  minPrimarySize = 200,
 52â†’  onPrimaryCollapse,
 53â†’  isPrimaryCollapsed = false,
 54â†’  onPrimaryExpand,
 55â†’}: UseResizeHandleOptions): UseResizeHandleReturn {
 56â†’  const isDraggingRef = useRef(false);
 57â†’  const [isDragging, setIsDragging] = useState(false);
 58â†’  const cleanupRef = useRef<(() => void) | null>(null);
 59â†’  const isPrimaryCollapsedRef = useRef(isPrimaryCollapsed);
 60â†’
 61â†’  useEffect(() => {
 62â†’    isPrimaryCollapsedRef.current = isPrimaryCollapsed;
 63â†’  }, [isPrimaryCollapsed]);
 64â†’
 65â†’  useEffect(() => {
 66â†’    return () => {
 67â†’      cleanupRef.current?.();
 68â†’      cleanupRef.current = null;
 69â†’    };
 70â†’  }, []);
 71â†’
 72â†’  const handleMouseDown = useCallback(
 73â†’    (e: React.MouseEvent) => {
 74â†’      if (!enabled) return;
 75â†’      e.preventDefault();
 76â†’
 77â†’      isDraggingRef.current = true;
 78â†’      setIsDragging(true);
 79â†’
 80â†’      const handle = e.currentTarget as HTMLElement;
 81â†’      const container = handle.parentElement;
 82â†’      if (!container) {
 83â†’        isDraggingRef.current = false;
 84â†’        setIsDragging(false);
 85â†’        return;
 86â†’      }
 87â†’
 88â†’      const onMouseMove = (moveEvent: MouseEvent) => {
 89â†’        if (!isDraggingRef.current) return;
 90â†’
 91â†’        const rect = container.getBoundingClientRect();
 92â†’        const totalSize = direction === "horizontal" ? rect.width : rect.height;
 93â†’
 94â†’        // Raw primary size (before clamping) for snap-to-collapse detection
 95â†’        const rawPrimaryOffset =
 96â†’          direction === "horizontal" ? moveEvent.clientX - rect.left : moveEvent.clientY - rect.top;
 97â†’
 98â†’        // Bidirectional snap points:
 99â†’        // - Collapse when dragging well below minPrimarySize.
100â†’        // - Re-expand when dragging back beyond minPrimarySize.
101â†’        // This creates a dead zone / hysteresis that prevents jitter.
102â†’        const collapseThreshold = minPrimarySize * 0.5;
103â†’        const expandThreshold = minPrimarySize;
104â†’        const currentlyCollapsed = isPrimaryCollapsedRef.current;
105â†’
106â†’        if (!currentlyCollapsed && onPrimaryCollapse && rawPrimaryOffset < collapseThreshold) {
107â†’          isPrimaryCollapsedRef.current = true;
108â†’          onPrimaryCollapse();
109â†’          return;
110â†’        }
111â†’
112â†’        if (currentlyCollapsed && onPrimaryExpand && rawPrimaryOffset > expandThreshold) {
113â†’          isPrimaryCollapsedRef.current = false;
114â†’          onPrimaryExpand();
115â†’        }
116â†’
117â†’        if (isPrimaryCollapsedRef.current) {
118â†’          return;
119â†’        }
120â†’
121â†’        if (mode === "primary") {
122â†’          // Primary mode: report left/top panel size
123â†’          let newPrimarySize = rawPrimaryOffset;
124â†’          const maxPrimarySize = Math.max(0, totalSize - minSecondarySize);
125â†’          newPrimarySize = Math.max(newPrimarySize, Math.min(minPrimarySize, maxPrimarySize));
126â†’          newPrimarySize = Math.min(newPrimarySize, maxPrimarySize);
127â†’          onSizeChange(Math.round(newPrimarySize));
128â†’        } else {
129â†’          // Secondary mode (default): report right/bottom panel size
130â†’          const newSecondaryRaw = totalSize - rawPrimaryOffset;
131â†’          const maxSecondarySize = Math.max(0, totalSize - minPrimarySize);
132â†’          let newSecondarySize = Math.max(
133â†’            newSecondaryRaw,
134â†’            Math.min(minSecondarySize, maxSecondarySize)
135â†’          );
136â†’          newSecondarySize = Math.min(newSecondarySize, maxSecondarySize);
137â†’          onSizeChange(Math.round(newSecondarySize));
138â†’        }
139â†’      };
140â†’
141â†’      const cleanup = () => {
142â†’        isDraggingRef.current = false;
143â†’        setIsDragging(false);
144â†’        document.body.style.cursor = "";
145â†’        document.body.style.userSelect = "";
146â†’        document.removeEventListener("mousemove", onMouseMove);
147â†’        document.removeEventListener("mouseup", onMouseUp);
148â†’      };
149â†’
150â†’      const onMouseUp = () => {
151â†’        cleanup();
152â†’        cleanupRef.current = null;
153â†’      };
154â†’
155â†’      document.body.style.cursor = direction === "horizontal" ? "col-resize" : "row-resize";
156â†’      document.body.style.userSelect = "none";
157â†’      document.addEventListener("mousemove", onMouseMove);
158â†’      document.addEventListener("mouseup", onMouseUp);
159â†’      cleanupRef.current = cleanup;
160â†’    },
161â†’    [
162â†’      enabled,
163â†’      direction,
164â†’      mode,
165â†’      minSecondarySize,
166â†’      minPrimarySize,
167â†’      onSizeChange,
168â†’      onPrimaryCollapse,
169â†’      onPrimaryExpand,
170â†’    ]
171â†’  );
172â†’
173â†’  const handleDoubleClick = useCallback(() => {
174â†’    if (!enabled) return;
175â†’    onSizeChange(null);
176â†’  }, [enabled, onSizeChange]);
177â†’
178â†’  return {
179â†’    handleProps: {
180â†’      onMouseDown: handleMouseDown,
181â†’      onDoubleClick: handleDoubleClick,
182â†’    },
183â†’    isDragging,
184â†’  };
185â†’}
