/**
 * Content Tab Bar -- icon tab switcher for the content panel header.
 *
 * Renders inside the content panel's header bar (36px), left-aligned.
 * Active tab: filled pill (bg-bg-raised) with icon + text label.
 * Inactive tabs: icon only with tooltip on hover.
 *
 * The parent (MainContent) owns tab change logic. This component is pure
 * presentation -- it renders icons/pills and fires onTabChange.
 */

import { useMemo } from "react";
import { GitBranch, Bot, Terminal, BookOpen, PenTool, Globe, Smartphone } from "lucide-react";
import { Tooltip, TooltipTrigger, TooltipContent } from "@/components/ui/tooltip";
import { cn } from "@/shared/lib/utils";
import { useSettings } from "@/features/settings/api/settings.queries";
import { useSimulatorStatusStore } from "@/features/simulator/store";
import type { RightSideTab } from "@/features/workspace/store";
import type { Settings } from "@shared/types/settings";

interface ContentTabBarProps {
  activeTab: RightSideTab;
  onTabChange: (tab: RightSideTab) => void;
  workspaceId?: string | null;
}

const contentTabItems: Array<{
  id: RightSideTab;
  label: string;
  icon: typeof GitBranch;
  /** Settings key that controls visibility. Absent = always visible. */
  visibilityKey?: keyof Settings;
}> = [
  { id: "code", label: "Code", icon: GitBranch },
  { id: "terminal", label: "Terminal", icon: Terminal },
  { id: "notebook", label: "Notebook", icon: BookOpen, visibilityKey: "experimental_notebooks" },
  { id: "design", label: "Design", icon: PenTool, visibilityKey: "experimental_design" },
  { id: "browser", label: "Browser", icon: Globe, visibilityKey: "experimental_browser" },
  {
    id: "simulator",
    label: "Simulator",
    icon: Smartphone,
    visibilityKey: "experimental_simulator",
  },
  { id: "config", label: "Agent", icon: Bot },
];

/** Check if a tab should be visible given current settings. undefined = hidden (opt-in). */
export function isTabVisible(tab: RightSideTab, settings?: Settings): boolean {
  const item = contentTabItems.find((i) => i.id === tab);
  if (!item?.visibilityKey) return true;
  return settings?.[item.visibilityKey] === true;
}

/**
 * ContentTabBar -- horizontal tab bar for the right content panel header.
 *
 * Active tab: filled pill with icon + label (h-7, rounded-lg).
 * Inactive tabs: icon-only buttons with tooltips.
 * No container/track background â€” tabs sit directly in the header.
 */
export function ContentTabBar({ activeTab, onTabChange, workspaceId }: ContentTabBarProps) {
  const settings = useSettings().data;
  const simPhase = useSimulatorStatusStore((s) =>
    workspaceId ? s.phases[workspaceId] : undefined
  );

  // Show a dot when the simulator is doing something (not idle, not absent)
  const simulatorActive = simPhase && simPhase !== "idle";

  const visibleItems = useMemo(
    () => contentTabItems.filter((item) => isTabVisible(item.id, settings)),
    [settings]
  );

  return (
    <div
      data-slot="content-tab-bar"
      className="flex items-center gap-1"
      role="tablist"
      aria-label="Content panel"
    >
      {visibleItems.map((item) => {
        const Icon = item.icon;
        const isActive = activeTab === item.id;
        const showDot = item.id === "simulator" && simulatorActive;

        return isActive ? (
          <button
            key={item.id}
            type="button"
            role="tab"
            aria-label={item.label}
            aria-selected={true}
            onClick={() => onTabChange(item.id)}
            className={cn(
              "bg-bg-raised text-text-secondary",
              "relative flex h-7 items-center gap-1.5 rounded-lg px-3",
              "text-sm font-medium",
              "transition-colors duration-150"
            )}
          >
            <Icon className="h-[13px] w-[13px]" />
            <span>{item.label}</span>
            {showDot && (
              <span className="bg-success absolute -top-0.5 -right-0.5 h-2 w-2 rounded-full" />
            )}
          </button>
        ) : (
          <Tooltip key={item.id} delayDuration={300}>
            <TooltipTrigger asChild>
              <button
                type="button"
                role="tab"
                aria-label={item.label}
                aria-selected={false}
                onClick={() => onTabChange(item.id)}
                className={cn(
                  "text-text-muted hover:text-text-secondary hover:bg-bg-muted",
                  "relative flex h-7 items-center justify-center rounded-lg px-2",
                  "transition-colors duration-150"
                )}
              >
                <Icon className="h-3.5 w-3.5" />
                {showDot && (
                  <span className="bg-success absolute -top-0.5 -right-0.5 h-2 w-2 rounded-full" />
                )}
              </button>
            </TooltipTrigger>
            <TooltipContent side="bottom" sideOffset={8}>
              <p className="text-xs">{item.label}</p>
            </TooltipContent>
          </Tooltip>
        );
      })}
    </div>
  );
}

import { Settings2 } from "lucide-react";
import { ScrollArea } from "@/components/ui/scroll-area";
import { useAgents, useMCPServers, useSettings } from "@/features/settings/api/settings.queries";

export function ConfigPanel() {
  const settings = useSettings().data;
  const mcpServersQuery = useMCPServers();
  const agentsQuery = useAgents();

  const mcpServers = mcpServersQuery.data || [];
  const agents = agentsQuery.data || [];

  const provider = settings?.claude_provider || "Anthropic";
  const model = settings?.claude_model || "Default model";
  const contextWindowLabel = "Not available";
  const contextWindowPercent = "0%";

  return (
    <div className="flex h-full flex-col">
      <div className="border-border/40 flex h-9 items-center gap-2 border-b px-4">
        <Settings2 className="text-muted-foreground h-4 w-4" />
        <span className="text-sm font-medium">Agent Config</span>
      </div>

      <ScrollArea className="flex-1">
        <div className="space-y-5 p-4">
          <section className="space-y-2">
            <p className="text-muted-foreground text-xs font-semibold tracking-wide uppercase">
              Model
            </p>
            <div className="border-border/40 bg-muted/30 flex items-center justify-between rounded-lg border px-3 py-2 text-xs">
              <span className="text-muted-foreground">Provider</span>
              <span className="text-foreground font-medium">{provider}</span>
            </div>
            <div className="border-border/40 bg-muted/30 flex items-center justify-between rounded-lg border px-3 py-2 text-xs">
              <span className="text-muted-foreground">Model</span>
              <span className="text-foreground font-medium">{model}</span>
            </div>
          </section>

          <section className="space-y-2">
            <p className="text-muted-foreground text-xs font-semibold tracking-wide uppercase">
              MCP Servers
            </p>
            {mcpServers.length === 0 ? (
              <div className="border-border/40 text-muted-foreground bg-muted/30 rounded-lg border border-dashed px-3 py-4 text-xs">
                No MCP servers configured
              </div>
            ) : (
              <div className="border-border/40 divide-border/40 overflow-hidden rounded-lg border">
                {mcpServers.map((server, index) => (
                  <div
                    key={`${server.name}-${index}`}
                    className="border-border/40 flex items-start justify-between gap-3 border-b px-3 py-2 text-xs last:border-b-0"
                  >
                    <div className="text-foreground font-medium">{server.name}</div>
                    <div className="text-muted-foreground truncate font-mono">{server.command}</div>
                  </div>
                ))}
              </div>
            )}
          </section>

          <section className="space-y-2">
            <p className="text-muted-foreground text-xs font-semibold tracking-wide uppercase">
              Loaded Skills
            </p>
            {agents.length === 0 ? (
              <div className="border-border/40 text-muted-foreground bg-muted/30 rounded-lg border border-dashed px-3 py-4 text-xs">
                Using default agents
              </div>
            ) : (
              <div className="flex flex-wrap gap-2">
                {agents.map((agent) => (
                  <span
                    key={agent.id}
                    className="border-border/40 bg-muted/40 text-foreground rounded-full border px-2.5 py-1 text-xs font-medium"
                  >
                    {agent.name}
                  </span>
                ))}
              </div>
            )}
          </section>

          <section className="space-y-2">
            <div className="flex items-center justify-between">
              <p className="text-muted-foreground text-xs font-semibold tracking-wide uppercase">
                Context Window
              </p>
              <span className="text-muted-foreground text-xs">{contextWindowLabel}</span>
            </div>
            <div className="bg-muted/40 h-2 w-full overflow-hidden rounded-full">
              <div
                className="bg-success/60 h-full rounded-full"
                style={{
                  width: contextWindowPercent,
                }}
              />
            </div>
            <p className="text-muted-foreground text-xs">
              Context usage metrics are not wired yet.
            </p>
          </section>
        </div>
      </ScrollArea>
    </div>
  );
}

